window.botTrack=(e,t={})=>{window.dataLayer&&window.dataLayer.push({event:e,...t})};document.querySelectorAll(".reveal").forEach(e=>e.classList.add("will-animate"));const l=new IntersectionObserver(e=>{e.forEach(t=>{if(!t.isIntersecting)return;const a=[...t.target.parentElement?.querySelectorAll(".reveal")||[]].indexOf(t.target);setTimeout(()=>t.target.classList.add("on"),a*90),l.unobserve(t.target)})},{threshold:.04,rootMargin:"0px"});document.querySelectorAll(".reveal").forEach(e=>l.observe(e));setTimeout(()=>{document.querySelectorAll(".reveal.will-animate:not(.on)").forEach(e=>e.classList.add("on"))},1e3);const c=document.getElementById("nav"),r=document.getElementById("nav-menu-btn"),n=document.getElementById("mobile-sheet"),o=document.getElementById("mobile-overlay");window.addEventListener("scroll",()=>{c.classList.toggle("scrolled",window.scrollY>10)},{passive:!0});function d(){n.classList.add("open"),o.classList.add("open"),document.body.style.overflow="hidden"}function s(){n.classList.remove("open"),o.classList.remove("open"),document.body.style.overflow=""}r.addEventListener("click",d);o.addEventListener("click",s);n.querySelectorAll("a").forEach(e=>e.addEventListener("click",s));document.addEventListener("keydown",e=>{e.key==="Escape"&&s()});
